import{_ as a,c as t,a1 as s,o as e}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Sử dụng Social Engineering Toolkit (SET)","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md","filePath":"vi/categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md"}'),i={name:"vi/categories/ethical-hacking-labs/8-social-engineering/1-Using-SET.md"};function c(p,n,o,h,l,r){return e(),t("div",null,n[0]||(n[0]=[s(`<h1 id="su-dung-social-engineering-toolkit-set" tabindex="-1">Sử dụng Social Engineering Toolkit (SET) <a class="header-anchor" href="#su-dung-social-engineering-toolkit-set" aria-label="Permalink to &quot;Sử dụng Social Engineering Toolkit (SET)&quot;">​</a></h1><p>Social Engineering Toolkit (SET) là một công cụ mã nguồn mở được viết bằng Python, được thiết kế cho kiểm thử thâm nhập (pentesting). SET được thiết kế đặc biệt để thực hiện các cuộc tấn công nâng cao chống lại con người bằng cách khai thác hành vi của họ. Các cuộc tấn công được tích hợp trong toolkit được thiết kế để nhắm mục tiêu cụ thể vào một cá nhân hoặc tổ chức được sử dụng trong quá trình kiểm thử thâm nhập.</p><p><em>Hướng dẫn sử dụng SET bởi TrustedSec: <a href="https://github.com/trustedsec/social-engineer-toolkit/raw/master/readme/User_Manual.pdf" target="_blank" rel="noreferrer">https://github.com/trustedsec/social-engineer-toolkit/raw/master/readme/User_Manual.pdf</a></em></p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Sao chép một trang web</li><li>Thu thập tên người dùng và mật khẩu</li><li>Tạo báo cáo cho bài kiểm thử thâm nhập đã thực hiện</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux</li><li>Bất kỳ máy ảo Windows nào</li></ul><h2 id="khoi-chay-set" tabindex="-1">Khởi chạy SET <a class="header-anchor" href="#khoi-chay-set" aria-label="Permalink to &quot;Khởi chạy SET&quot;">​</a></h2><p>Đăng nhập vào Kali Linux; Hãy nhớ rằng mỗi phiên bản Kali đều đi kèm với SET được cài đặt sẵn, để khởi chạy <em>(trên Kali 2019.4)</em> hãy vào <strong>Kali Menu &gt; 13 - Social Engineering Tools &gt; SET (Social Engineering Toolkit).</strong></p><p>Chấp nhận Điều khoản Dịch vụ bằng cách gõ <strong>y</strong>.</p><h2 id="sao-chep-mot-trang-web" tabindex="-1">Sao chép một trang Web <a class="header-anchor" href="#sao-chep-mot-trang-web" aria-label="Permalink to &quot;Sao chép một trang Web&quot;">​</a></h2><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4fa403cfe8f17a4771b15cab4dfa28cbcaff1385/set-0.png" alt="set-0"></p><p>Trên menu chính của SET, chọn tùy chọn đầu tiên <strong>1) Social-Engineering Attacks</strong> bằng cách nhập số:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Select from the menu:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   1) Social-Engineering Attacks</span></span>
<span class="line"><span>   2) Penetration Testing (Fast-Track)</span></span>
<span class="line"><span>   3) Third Party Modules</span></span>
<span class="line"><span>   4) Update the Social-Engineer Toolkit</span></span>
<span class="line"><span>   5) Update SET configuration</span></span>
<span class="line"><span>   6) Help, Credits, and About</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Exit the Social-Engineer Toolkit</span></span></code></pre></div><p>Tiếp theo, chọn <strong>2) Website Attack Vectors</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Select from the menu:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   1) Spear-Phishing Attack Vectors</span></span>
<span class="line"><span>   2) Website Attack Vectors</span></span>
<span class="line"><span>   3) Infectious Media Generator</span></span>
<span class="line"><span>   4) Create a Payload and Listener</span></span>
<span class="line"><span>   5) Mass Mailer Attack</span></span>
<span class="line"><span>   6) Arduino-Based Attack Vector</span></span>
<span class="line"><span>   7) Wireless Access Point Attack Vector</span></span>
<span class="line"><span>   8) QRCode Generator Attack Vector</span></span>
<span class="line"><span>   9) Powershell Attack Vectors</span></span>
<span class="line"><span>  10) Third Party Modules</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return back to the main menu.</span></span></code></pre></div><p><strong>Web Attack Vector</strong> là một cách độc đáo để sử dụng nhiều cuộc tấn công dựa trên web nhằm xâm phạm mục tiêu dự định.</p><p>Trong menu tiếp theo, chọn <strong>3) Credential Harvester Attack Method</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   1) Java Applet Attack Method</span></span>
<span class="line"><span>   2) Metasploit Browser Exploit Method</span></span>
<span class="line"><span>   3) Credential Harvester Attack Method</span></span>
<span class="line"><span>   4) Tabnabbing Attack Method</span></span>
<span class="line"><span>   5) Web Jacking Attack Method</span></span>
<span class="line"><span>   6) Multi-Attack Web Method</span></span>
<span class="line"><span>   7) HTA Attack Method</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return to Main Menu</span></span></code></pre></div><p>Phương pháp Credential Harvester sẽ sử dụng việc sao chép web của một trang web có trường đăng nhập (trường tên người dùng và mật khẩu) và thu thập tất cả thông tin được gửi đến trang web.</p><p>Tiếp theo, chọn <strong>2) Site Cloner</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   1) Web Templates</span></span>
<span class="line"><span>   2) Site Cloner</span></span>
<span class="line"><span>   3) Custom Import</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  99) Return to Webattack Menu</span></span></code></pre></div><p>Site cloner được sử dụng để sao chép một tr web theo lựa chọn của bạn.</p><p>Tiếp theo, nhập <strong>địa chỉ IP của Kali Linux</strong> và URL cần sao chép, trong ví dụ này chúng ta sẽ sử dụng <em>facebook.com</em> như hình dưới:</p><p><img src="https://gist.github.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/91679b70b9db90d2be07da923f17f8ff74341609/set-1.png" alt="set-1"></p><p>Sau đó, để tab terminal này chạy.</p><h2 id="gui-mot-email-đuoc-tao-san" tabindex="-1">Gửi một Email được tạo sẵn <a class="header-anchor" href="#gui-mot-email-đuoc-tao-san" aria-label="Permalink to &quot;Gửi một Email được tạo sẵn&quot;">​</a></h2><p>Bây giờ bạn phải gửi <strong>địa chỉ IP</strong> của máy <strong>Kali</strong> đến mục tiêu, và lừa họ nhấp vào liên kết.</p><p>Trong demo này, chúng ta sẽ sử dụng <strong>Gmail</strong>; Khởi chạy trình duyệt web trên Kali và đăng nhập vào tài khoản Gmail để soạn email.</p><p>Ví dụ này sẽ chỉ trình bày khía cạnh kỹ thuật của kỹ thuật này.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1097d5dacdd68740924956c6632fb4e0be50ee3a/set-2.png" alt="set-2"></p><p>Để tạo một liên kết đúng, nhấp vào <strong>edit link</strong> và trước tiên nhập địa chỉ thực vào mục <strong>Link to</strong>, sau đó nhập URL giả vào trường <strong>Text to display</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/22c46de6cebebea15399154a331120c8a3721090/set-3.png" alt="set-3"></p><p>Bạn có thể xác minh URL giả bằng cách nhấp một lần, nó sẽ hiển thị URL thực.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1097d5dacdd68740924956c6632fb4e0be50ee3a/set-4.png" alt="set-4"></p><h2 id="đang-nhap-vao-trang-web-đa-sao-chep" tabindex="-1">Đăng nhập vào trang Web đã sao chép <a class="header-anchor" href="#đang-nhap-vao-trang-web-đa-sao-chep" aria-label="Permalink to &quot;Đăng nhập vào trang Web đã sao chép&quot;">​</a></h2><p>Đăng nhập vào <strong>Windows</strong> với tư cách là nạn nhân, khởi chạy trình duyệt web và đăng nhập vào email của bạn (tài khoản mà bạn đã gửi email phishing).</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/a896b360ac4d9ff1fabcf2825ac0488151defa86/set-5.png" alt="set-5"></p><p>Khi nạn nhân nhấp vào URL, họ sẽ thấy một bản sao của facebook.com. Nạn nhân sẽ được yêu cầu nhập tên người dùng và mật khẩu vào các trường biểu mẫu. Sau khi nạn nhân nhập Tên người dùng và Mật khẩu và nhấp đăng nhập, hệ thống không cho phép đăng nhập; thay vào đó, nó chuyển hướng đến trang đăng nhập Facebook hợp pháp, hãy quan sát URL.</p><h2 id="thu-thap-thong-tin-đang-nhap" tabindex="-1">Thu thập thông tin đăng nhập <a class="header-anchor" href="#thu-thap-thong-tin-đang-nhap" aria-label="Permalink to &quot;Thu thập thông tin đăng nhập&quot;">​</a></h2><p><strong>SET</strong> trên Kali Linux sẽ lấy <strong>tên người dùng</strong> và <strong>mật khẩu</strong> đã nhập, có thể được sử dụng bởi kẻ tấn công để truy cập trái phép vào tài khoản của nạn nhân.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/4f9889f8bf9605f0e4cd1a415f71a77d73eedaee/set-7.png" alt="set-7"></p>`,42)]))}const u=a(i,[["render",c]]);export{d as __pageData,u as default};
